import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

const SYSTEM_PROMPT = `
You are a credit risk analyst. Reason through each application step by step
using the format shown in the examples, then state the decision.

Example:
Application: Income $45,000/yr, existing debt $500/mo, requested loan $200,000, rate 6.5%
Step 1: Monthly income = 45000 / 12 = $3,750
Step 2: Proposed monthly payment = 200000 * 0.065 / 12 * (1+0.065/12)^360 / ((1+0.065/12)^360 - 1) ≈ $1,264
Step 3: Total debt-to-income = (500 + 1264) / 3750 = 47% — exceeds 43% threshold
Decision: DECLINE — DTI above threshold
`.trim();

async function analyseApplication(details) {
  const msg = await client.messages.create({
    model: "claude-opus-4-5",
    max_tokens: 512,
    system: SYSTEM_PROMPT,
    messages: [{ role: "user", content: `Application: ${details}` }],
  });

  const text = msg.content[0].text;
  const decision = text.match(/Decision:\s*(.+)/)?.[1] ?? "unknown";
  return { reasoning: text, decision };
}

const result = await analyseApplication(
  "Income $72,000/yr, existing debt $300/mo, requested loan $220,000, rate 7.0%"
);
console.log("Reasoning trace:\n", result.reasoning);
console.log("Decision:", result.decision);

import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-5",   # extended thinking supported
    max_tokens=16000,
    thinking={
        "type": "enabled",
        "budget_tokens": 10000,  # max tokens for the thinking block
    },
    messages=[{
        "role": "user",
        "content": "Prove that the square root of 2 is irrational."
    }],
)

for block in response.content:
    if block.type == "thinking":
        print("Thinking trace:\n", block.thinking)
    elif block.type == "text":
        print("\nFinal answer:\n", block.text)
